fun createIndex(indexName: String) {
    esClient.indices().create { req ->
        req.index(indexName)
           .settings { s ->
               s.analysis { a ->
                   a.analyzer("nori_analyzer") { an ->
                       an.custom { c -> c.tokenizer("nori_tokenizer") }
                   }
               }
           }
           .mappings { m ->
               m.properties("name") { p ->
                   p.text { t -> t.analyzer("nori_analyzer") }
               }
           }
}
